syntaxExplanation:
try:
    num = int(input('Enter number: '))
    res = 10 / num
except ZeroDivisionError:
    print('Cannot divide by zero!')
except ValueError:
    print('Invalid number format!')
else:
    print('Result:', res)
finally:
    print('Cleanup complete.')

